class Solution:
    def countValidSelections(self, nums):
        n = len(nums)
        total = 0
        for start in range(n):
            if nums[start] != 0:
                continue
            for d in (1, -1):
                arr = list(nums)
                curr = start
                direction = d
                steps_left = 10 ** 7
                while 0 <= curr < n and steps_left > 0:
                    if arr[curr] == 0:
                        curr += direction
                    else:
                        arr[curr] -= 1
                        direction = -direction
                        curr += direction
                    steps_left -= 1
                if all(v == 0 for v in arr):
                    total += 1
        return total

