var countValidSelections = function(nums) {
    const n = nums.length;
    let count = 0;
    for (let start = 0; start < n; start++) {
        if (nums[start] !== 0) continue;
        for (const direction of [1, -1]) {
            const arr = nums.slice();
            let curr = start;
            let d = direction;
            while (curr >= 0 && curr < n) {
                if (arr[curr] === 0) {
                    curr += d;
                } else {
                    arr[curr] -= 1;
                    d = -d;
                    curr += d;
                }
            }
            if (arr.every(v => v === 0)) count++;
        }
    }
    return count;
};
